import{_ as d,o as e,c as a,a2 as r}from"./chunks/framework._O8Cueap.js";const b=JSON.parse('{"title":"Support Tables","description":"","frontmatter":{},"headers":[],"relativePath":"database/schema-support.md","filePath":"database/schema-support.md"}'),o={name:"database/schema-support.md"};function s(i,t,n,c,h,l){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="support-tables" tabindex="-1">Support Tables <a class="header-anchor" href="#support-tables" aria-label="Permalink to &quot;Support Tables&quot;">​</a></h1><p>Variables, Admin &amp; Rate Limit, Audit &amp; Memory, and Auth &amp; Token tables. For the ER diagram and enums, see <a href="/open-agent-orchestra/database/schema.html">Schema Overview</a>.</p><h2 id="variable-tables" tabindex="-1">Variable Tables <a class="header-anchor" href="#variable-tables" aria-label="Permalink to &quot;Variable Tables&quot;">​</a></h2><p>All variable tables share the same structure: <code>key</code> (UPPER_SNAKE_CASE), <code>valueEncrypted</code> (AES-256-GCM), <code>variableType</code> (credential/property), <code>injectAsEnvVariable</code>, and a monotonically increasing <code>version</code>.</p><h3 id="agent-variables" tabindex="-1">agent_variables <a class="header-anchor" href="#agent-variables" aria-label="Permalink to &quot;agent_variables&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>agentId</td><td>UUID FK → agents</td><td></td></tr><tr><td>key</td><td>varchar(100)</td><td>UPPER_SNAKE_CASE</td></tr><tr><td>valueEncrypted</td><td>text</td><td>AES-256-GCM</td></tr><tr><td>description</td><td>varchar(300)</td><td></td></tr><tr><td>variableType</td><td>variable_type</td><td>Default: <code>credential</code></td></tr><tr><td>injectAsEnvVariable</td><td>boolean</td><td></td></tr><tr><td>version</td><td>integer</td><td>Auto-incremented on each update</td></tr><tr><td>createdAt, updatedAt</td><td>timestamp</td><td></td></tr><tr><td></td><td></td><td>UNIQUE(agentId, key)</td></tr></tbody></table><h3 id="user-variables" tabindex="-1">user_variables <a class="header-anchor" href="#user-variables" aria-label="Permalink to &quot;user_variables&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>userId</td><td>UUID</td><td></td></tr><tr><td>key</td><td>varchar(100)</td><td></td></tr><tr><td>valueEncrypted</td><td>text</td><td></td></tr><tr><td>description</td><td>varchar(300)</td><td></td></tr><tr><td>variableType</td><td>variable_type</td><td>Default: <code>credential</code></td></tr><tr><td>injectAsEnvVariable</td><td>boolean</td><td></td></tr><tr><td>version</td><td>integer</td><td>Auto-incremented on each update</td></tr><tr><td>createdAt, updatedAt</td><td>timestamp</td><td></td></tr><tr><td></td><td></td><td>UNIQUE(userId, key)</td></tr></tbody></table><h3 id="workspace-variables" tabindex="-1">workspace_variables <a class="header-anchor" href="#workspace-variables" aria-label="Permalink to &quot;workspace_variables&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workspaceId</td><td>UUID FK → workspaces</td><td></td></tr><tr><td>key</td><td>varchar(100)</td><td></td></tr><tr><td>valueEncrypted</td><td>text</td><td></td></tr><tr><td>description</td><td>varchar(300)</td><td></td></tr><tr><td>variableType</td><td>variable_type</td><td>Default: <code>credential</code></td></tr><tr><td>injectAsEnvVariable</td><td>boolean</td><td></td></tr><tr><td>version</td><td>integer</td><td>Auto-incremented on each update</td></tr><tr><td>createdAt, updatedAt</td><td>timestamp</td><td></td></tr><tr><td></td><td></td><td>UNIQUE(workspaceId, key)</td></tr></tbody></table><h3 id="variable-versions" tabindex="-1">variable_versions <a class="header-anchor" href="#variable-versions" aria-label="Permalink to &quot;variable_versions&quot;">​</a></h3><p>Immutable metadata snapshots for variables across all three scopes.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>variableId</td><td>UUID</td><td>Original variable ID (no FK so history survives deletion)</td></tr><tr><td>scope</td><td>variable_scope</td><td><code>agent</code>, <code>user</code>, or <code>workspace</code></td></tr><tr><td>scopeId</td><td>UUID</td><td>Owner ID for the variable&#39;s scope</td></tr><tr><td>workspaceId</td><td>UUID</td><td>Workspace context for access checks</td></tr><tr><td>version</td><td>integer</td><td>Snapshot version number</td></tr><tr><td>snapshot</td><td>jsonb</td><td>Variable metadata snapshot, including deleted state</td></tr><tr><td>changedBy</td><td>UUID</td><td>User who made the change</td></tr><tr><td>createdAt</td><td>timestamp</td><td></td></tr><tr><td></td><td></td><td>UNIQUE(scope, variableId, version)</td></tr></tbody></table><h2 id="admin-rate-limit-tables" tabindex="-1">Admin &amp; Rate Limit Tables <a class="header-anchor" href="#admin-rate-limit-tables" aria-label="Permalink to &quot;Admin &amp; Rate Limit Tables&quot;">​</a></h2><h3 id="models" tabindex="-1">models <a class="header-anchor" href="#models" aria-label="Permalink to &quot;models&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workspaceId</td><td>UUID FK → workspaces</td><td></td></tr><tr><td>name</td><td>varchar(100)</td><td>UNIQUE per workspace</td></tr><tr><td>provider</td><td>varchar(50)</td><td>Default: <code>github</code></td></tr><tr><td>description</td><td>text</td><td></td></tr><tr><td>creditCost</td><td>decimal(10,2)</td><td>Default: 1.00</td></tr><tr><td>isActive</td><td>boolean</td><td></td></tr><tr><td>createdAt, updatedAt</td><td>timestamp</td><td></td></tr></tbody></table><h3 id="workspace-quota-settings" tabindex="-1">workspace_quota_settings <a class="header-anchor" href="#workspace-quota-settings" aria-label="Permalink to &quot;workspace_quota_settings&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workspaceId</td><td>UUID FK</td><td>UNIQUE</td></tr><tr><td>dailyCreditLimit</td><td>decimal(10,2)</td><td>Null = unlimited</td></tr><tr><td>weeklyCreditLimit</td><td>decimal(10,2)</td><td>Null = unlimited</td></tr><tr><td>monthlyCreditLimit</td><td>decimal(10,2)</td><td>Null = unlimited</td></tr><tr><td>updatedBy</td><td>UUID FK → users</td><td></td></tr><tr><td>updatedAt</td><td>timestamp</td><td></td></tr></tbody></table><h3 id="user-quota-settings" tabindex="-1">user_quota_settings <a class="header-anchor" href="#user-quota-settings" aria-label="Permalink to &quot;user_quota_settings&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>userId</td><td>UUID FK</td><td>UNIQUE</td></tr><tr><td>dailyCreditLimit</td><td>decimal(10,2)</td><td>Null = use workspace default</td></tr><tr><td>weeklyCreditLimit</td><td>decimal(10,2)</td><td>Null = use workspace default</td></tr><tr><td>monthlyCreditLimit</td><td>decimal(10,2)</td><td>Null = use workspace default</td></tr><tr><td>updatedAt</td><td>timestamp</td><td></td></tr></tbody></table><h3 id="credit-usage" tabindex="-1">credit_usage <a class="header-anchor" href="#credit-usage" aria-label="Permalink to &quot;credit_usage&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workspaceId</td><td>UUID FK</td><td></td></tr><tr><td>userId</td><td>UUID FK</td><td></td></tr><tr><td>modelName</td><td>varchar(100)</td><td></td></tr><tr><td>creditCostSnapshot</td><td>decimal(10,2)</td><td>Stored model credit cost at execution time</td></tr><tr><td>creditsConsumed</td><td>decimal(10,2)</td><td>Default: 0</td></tr><tr><td>sessionCount</td><td>integer</td><td></td></tr><tr><td>date</td><td>date</td><td></td></tr><tr><td>createdAt</td><td>timestamp</td><td></td></tr><tr><td></td><td></td><td>UNIQUE(userId, modelName, date, creditCostSnapshot)</td></tr></tbody></table><h2 id="audit-memory-tables" tabindex="-1">Audit &amp; Memory Tables <a class="header-anchor" href="#audit-memory-tables" aria-label="Permalink to &quot;Audit &amp; Memory Tables&quot;">​</a></h2><h3 id="system-events" tabindex="-1">system_events <a class="header-anchor" href="#system-events" aria-label="Permalink to &quot;system_events&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>eventScope</td><td>enum(<code>workspace</code>, <code>user</code>)</td><td></td></tr><tr><td>scopeId</td><td>UUID</td><td>workspaceId or userId</td></tr><tr><td>eventName</td><td>varchar(100)</td><td>One of 21 predefined events</td></tr><tr><td>eventData</td><td>jsonb</td><td>Event-specific payload</td></tr><tr><td>actorId</td><td>UUID</td><td>User who caused the event</td></tr><tr><td>createdAt</td><td>timestamp</td><td>Indexed for cursor-based polling</td></tr></tbody></table><h3 id="agent-decisions" tabindex="-1">agent_decisions <a class="header-anchor" href="#agent-decisions" aria-label="Permalink to &quot;agent_decisions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>agentId</td><td>UUID FK</td><td></td></tr><tr><td>executionId</td><td>UUID FK</td><td></td></tr><tr><td>category</td><td>varchar(50)</td><td>e.g., <code>trade</code>, <code>analysis</code></td></tr><tr><td>action</td><td>varchar(50)</td><td>e.g., <code>buy</code>, <code>approve</code></td></tr><tr><td>summary</td><td>text</td><td></td></tr><tr><td>decision</td><td>jsonb</td><td>Full reasoning</td></tr><tr><td>outcome</td><td>varchar(20)</td><td><code>executed</code>, <code>rejected</code>, <code>skipped</code></td></tr><tr><td>referenceId</td><td>varchar(100)</td><td>External reference</td></tr><tr><td>createdAt</td><td>timestamp</td><td></td></tr></tbody></table><h3 id="agent-memories" tabindex="-1">agent_memories <a class="header-anchor" href="#agent-memories" aria-label="Permalink to &quot;agent_memories&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>agentId</td><td>UUID FK</td><td></td></tr><tr><td>content</td><td>text</td><td>Memory content</td></tr><tr><td>embedding</td><td>vector(1536)</td><td>pgvector embedding</td></tr><tr><td>metadata</td><td>jsonb</td><td>Additional context</td></tr><tr><td>createdAt</td><td>timestamp</td><td></td></tr></tbody></table><h3 id="agent-instances" tabindex="-1">agent_instances <a class="header-anchor" href="#agent-instances" aria-label="Permalink to &quot;agent_instances&quot;">​</a></h3><p>Tracks running agent instances (both static and ephemeral).</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>name</td><td>varchar(200)</td><td>Instance name (worker name or K8s pod name)</td></tr><tr><td>instance_type</td><td>enum</td><td><code>static</code> or <code>ephemeral</code></td></tr><tr><td>status</td><td>enum</td><td><code>idle</code>, <code>busy</code>, <code>offline</code>, <code>terminated</code></td></tr><tr><td>hostname</td><td>varchar(255)</td><td>Machine/container hostname</td></tr><tr><td>current_step_execution_id</td><td>UUID FK → step_executions</td><td>Currently executing step (nullable)</td></tr><tr><td>metadata</td><td>JSONB</td><td>Flexible metadata (pid, labels, etc.)</td></tr><tr><td>last_heartbeat_at</td><td>timestamp</td><td>Last heartbeat time</td></tr><tr><td>createdAt</td><td>timestamp</td><td></td></tr><tr><td>updatedAt</td><td>timestamp</td><td></td></tr></tbody></table><h3 id="webhook-registrations" tabindex="-1">webhook_registrations <a class="header-anchor" href="#webhook-registrations" aria-label="Permalink to &quot;webhook_registrations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>agentId</td><td>UUID FK</td><td></td></tr><tr><td>triggerId</td><td>UUID FK</td><td></td></tr><tr><td>endpointPath</td><td>varchar(200)</td><td>URL path suffix</td></tr><tr><td>hmacSecretEncrypted</td><td>text</td><td>AES-256-GCM</td></tr><tr><td>isActive</td><td>boolean</td><td></td></tr><tr><td>requestCount</td><td>integer</td><td></td></tr><tr><td>lastReceivedAt</td><td>timestamp</td><td></td></tr><tr><td>createdAt</td><td>timestamp</td><td></td></tr></tbody></table><h2 id="auth-token-tables" tabindex="-1">Auth &amp; Token Tables <a class="header-anchor" href="#auth-token-tables" aria-label="Permalink to &quot;Auth &amp; Token Tables&quot;">​</a></h2><h3 id="auth-providers" tabindex="-1">auth_providers <a class="header-anchor" href="#auth-providers" aria-label="Permalink to &quot;auth_providers&quot;">​</a></h3><p>Workspace-scoped authentication provider configurations. See <a href="/open-agent-orchestra/concepts/auth-providers.html">Auth Providers</a>.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workspaceId</td><td>UUID FK → workspaces</td><td></td></tr><tr><td>providerType</td><td>auth_provider_type</td><td><code>database</code> or <code>ldap</code></td></tr><tr><td>name</td><td>varchar(100)</td><td>Display name</td></tr><tr><td>isEnabled</td><td>boolean</td><td>Default: true</td></tr><tr><td>priority</td><td>integer</td><td>Lower = higher priority (default: 0)</td></tr><tr><td>config</td><td>jsonb</td><td>Provider-specific settings (LDAP URL, bind DN, etc.)</td></tr><tr><td>createdAt, updatedAt</td><td>timestamp</td><td></td></tr><tr><td></td><td></td><td>UNIQUE(workspaceId, providerType, name)</td></tr></tbody></table><h3 id="password-reset-tokens" tabindex="-1">password_reset_tokens <a class="header-anchor" href="#password-reset-tokens" aria-label="Permalink to &quot;password_reset_tokens&quot;">​</a></h3><p>Short-lived reset tokens for database-authenticated users.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>userId</td><td>UUID FK → users</td><td>Cascade delete</td></tr><tr><td>token</td><td>varchar(128)</td><td>Random hex token, unique</td></tr><tr><td>expiresAt</td><td>timestamp</td><td>Reset link expiry</td></tr><tr><td>usedAt</td><td>timestamp</td><td>Set after successful reset</td></tr><tr><td>createdAt</td><td>timestamp</td><td></td></tr></tbody></table><p>Workspace-level password reset enablement is stored on <code>workspaces.allowPasswordReset</code>.</p><h3 id="personal-access-tokens" tabindex="-1">personal_access_tokens <a class="header-anchor" href="#personal-access-tokens" aria-label="Permalink to &quot;personal_access_tokens&quot;">​</a></h3><p>Fine-grained PATs for webhook triggers and API access.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>userId</td><td>UUID FK → users</td><td>Cascade delete</td></tr><tr><td>workspaceId</td><td>UUID FK → workspaces</td><td>Cascade delete</td></tr><tr><td>name</td><td>varchar(100)</td><td>User-friendly label</td></tr><tr><td>tokenHash</td><td>varchar(128)</td><td>SHA-256 hash (UNIQUE)</td></tr><tr><td>tokenPrefix</td><td>varchar(12)</td><td>First 8 chars for display (<code>oao_xxxx</code>)</td></tr><tr><td>scopes</td><td>jsonb</td><td>Array of granted scopes</td></tr><tr><td>expiresAt</td><td>timestamp</td><td>Null = no expiry</td></tr><tr><td>lastUsedAt</td><td>timestamp</td><td>Updated on each use</td></tr><tr><td>isRevoked</td><td>boolean</td><td>Default: false</td></tr><tr><td>createdAt</td><td>timestamp</td><td></td></tr></tbody></table><p><strong>Available Scopes:</strong></p><table tabindex="0"><thead><tr><th>Scope</th><th>Description</th></tr></thead><tbody><tr><td><code>webhook:trigger</code></td><td>Trigger webhook-type workflow triggers</td></tr><tr><td><code>api:read</code></td><td>Read-only API access (GET endpoints)</td></tr><tr><td><code>api:write</code></td><td>Write API access (POST/PUT/DELETE)</td></tr><tr><td><code>api:agents</code></td><td>Manage agents</td></tr><tr><td><code>api:workflows</code></td><td>Manage workflows</td></tr><tr><td><code>api:executions</code></td><td>View/manage executions</td></tr><tr><td><code>api:variables</code></td><td>Read/write variables</td></tr><tr><td><code>api:triggers</code></td><td>Manage triggers</td></tr><tr><td><code>api:admin</code></td><td>Admin operations</td></tr></tbody></table>',47)])])}const m=d(o,[["render",s]]);export{b as __pageData,m as default};
